import "./styles/AdminStudents.css";
import { useState } from "react";

function AdminStudents() {
  const [students, setStudents] = useState([
    { id: 1, name: "Hari", email: "hari@rajagiri.edu", status: "Active" },
    { id: 2, name: "Anu", email: "anu@rajagiri.edu", status: "Blocked" },
    { id: 3, name: "Rahul", email: "rahul@rajagiri.edu", status: "Active" },
  ]);

  const toggleStatus = (id) => {
    setStudents(
      students.map((s) =>
        s.id === id
          ? { ...s, status: s.status === "Active" ? "Blocked" : "Active" }
          : s
      )
    );
  };

  return (
    <div className="admin-students-page">
      <h1 className="admin-title">Manage Students</h1>

      <table className="students-table">
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {students.map((s) => (
            <tr key={s.id}>
              <td>{s.name}</td>
              <td>{s.email}</td>
              <td
                className={
                  s.status === "Active" ? "status-active" : "status-blocked"
                }
              >
                {s.status}
              </td>
              <td>
                <button onClick={() => toggleStatus(s.id)}>
                  {s.status === "Active" ? "Block" : "Unblock"}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default AdminStudents;
